    .Skip(1)
    .Where(line => !string.IsNullOrWhiteSpace(line))
    .Select(line =>
    {
        var parts = line.Split(',');
        return new CustomerData
        {
            Age = float.Parse(parts[0].Trim()),
            Income = float.Parse(parts[1].Trim()),
            Region = parts[2].Trim(),
            PurchaseHistory = float.Parse(parts[3].Trim()),
            Churned = parts[4].Trim().Equals("Yes", StringComparison.OrdinalIgnoreCase),
        };
    })
    .ToList();

var allData = mlContext.Data.LoadFromEnumerable(records);
var split = mlContext.Data.TrainTestSplit(allData, testFraction: 0.2, seed: 42);

